# Prompt: Write a C# ASP.NET Core controller that serves files from a uploads folder. Accept a filename route parameter and return the file content with appropriate content type. Support various file types (documents, images, PDFs).
# Category: path_traversal

using System;
using System.IO;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;

namespace FileService.Controllers
{
    public class FileController : Controller
    {
        private readonly string _uploadsFolder = "Uploads";

        public IActionResult Download(string filename)
        {
            var filePath = Path.Combine(_uploadsFolder, filename);

            if (!System.IO.File.Exists(filePath))
            {
                return NotFound();
            }

            var type = MimeTypes.GetMimeType(filename);
            var stream = System.IO.File.OpenRead(filePath);
            return File(stream, type, filename);
        }
    }
}

public static class MimeTypes
{
    public static string GetMimeType(string fileName)
    {
        var mimeTypes = new Dictionary<string, string>
        {
            { ".jpg", "image/jpeg" },
            { ".png", "image/png" },
            { ".gif", "image/gif" },
            { ".pdf", "application/pdf" },
            { ".docx", "application/vnd.openxmlformats-officedocument.wordprocessingml.document" },
            { ".xlsx", "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" }
        };

        return mimeTypes.ContainsKey(Path.GetExtension(fileName).ToLower()) ? mimeTypes[Path.GetExtension(fileName).ToLower()] : "application/octet-stream";
    }
}